  1→// web/components/dashboard/activity-feed.tsx
  2→"use client";
  3→
  4→import { useEffect, useState, useRef } from "react";
  5→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
  6→import { Badge } from "@/components/ui/badge";
  7→import type { SSEEvent } from "@/lib/api/types";
  8→import { useTranslation } from "@/lib/i18n/context";
  9→
 10→const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
 11→
 12→const eventColors: Record<string, string> = {
 13→  release: "bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300",
 14→  semantic_release: "bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300",
 15→};
 16→
 17→function useEventFormatter() {
 18→  const { t } = useTranslation();
 19→
 20→  return function formatEvent(event: SSEEvent): string {
 21→    switch (event.type) {
 22→      case "release":
 23→        return `${t("dashboard.activity.newRelease")}: ${event.data.version}`;
 24→      case "semantic_release":
 25→        return `${t("dashboard.activity.semanticRelease")}: ${event.data.version} (${event.data.status})`;
 26→      default:
 27→        return t("dashboard.activity.unknownEvent");
 28→    }
 29→  };
 30→}
 31→
 32→export function ActivityFeed() {
 33→  const [events, setEvents] = useState<SSEEvent[]>([]);
 34→  const [connected, setConnected] = useState(false);
 35→  const retryRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 36→  const { t } = useTranslation();
 37→  const formatEvent = useEventFormatter();
 38→
 39→  useEffect(() => {
 40→    let es: EventSource | null = null;
 41→
 42→    function connect() {
 43→      try {
 44→        es = new EventSource(`${BASE}/events`);
 45→
 46→        es.onopen = () => setConnected(true);
 47→
 48→        es.onmessage = (msg) => {
 49→          try {
 50→            const event = JSON.parse(msg.data) as SSEEvent;
 51→            setEvents((prev) => [event, ...prev].slice(0, 20));
 52→          } catch {
 53→            // ignore parse errors
 54→          }
 55→        };
 56→
 57→        es.onerror = () => {
 58→          setConnected(false);
 59→          es?.close();
 60→          // Retry connection after 5 seconds
 61→          retryRef.current = setTimeout(connect, 5000);
 62→        };
 63→      } catch {
 64→        setConnected(false);
 65→        retryRef.current = setTimeout(connect, 5000);
 66→      }
 67→    }
 68→
 69→    connect();
 70→
 71→    return () => {
 72→      es?.close();
 73→      if (retryRef.current) clearTimeout(retryRef.current);
 74→    };
 75→  }, []);
 76→
 77→  return (
 78→    <Card>
 79→      <CardHeader>
 80→        <CardTitle className="flex items-center gap-2">
 81→          {t("dashboard.activity.title")}
 82→          <span className="relative flex h-2 w-2">
 83→            {connected ? (
 84→              <>
 85→                <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-green-400 opacity-75" />
 86→                <span className="relative inline-flex h-2 w-2 rounded-full bg-green-500" />
 87→              </>
 88→            ) : (
 89→              <span className="relative inline-flex h-2 w-2 rounded-full bg-text-muted" />
 90→            )}
 91→          </span>
 92→        </CardTitle>
 93→      </CardHeader>
 94→      <CardContent>
 95→        {events.length === 0 ? (
 96→          <p className="py-4 text-center text-sm text-muted-foreground">
 97→            {t("dashboard.activity.waiting")}
 98→          </p>
 99→        ) : (
100→          <div className="space-y-2 max-h-80 overflow-y-auto">
101→            {events.map((event) => (
102→              <div key={event.id} className="flex items-start gap-2 text-sm">
103→                <Badge className={`shrink-0 text-xs ${eventColors[event.type] ?? ""}`}>
104→                  {event.type}
105→                </Badge>
106→                <span className="flex-1 text-muted-foreground">{formatEvent(event)}</span>
107→                <span className="shrink-0 text-xs text-muted-foreground">
108→                  {new Date(event.timestamp).toLocaleTimeString()}
109→                </span>
110→              </div>
111→            ))}
112→          </div>
113→        )}
114→      </CardContent>
115→    </Card>
116→  );
117→}
