  1→// web/lib/api/types.ts
  2→
  3→// --- Response Envelope ---
  4→
  5→export interface ApiResponse<T> {
  6→  data: T;
  7→  meta?: ApiMeta;
  8→  error?: ApiError;
  9→}
 10→
 11→export interface ApiMeta {
 12→  page: number;
 13→  per_page: number;
 14→  total: number;
 15→}
 16→
 17→export interface ApiError {
 18→  code: string;
 19→  message: string;
 20→}
 21→
 22→// --- Domain Models (all IDs are UUID strings) ---
 23→
 24→export interface Project {
 25→  id: string;
 26→  name: string;
 27→  description?: string;
 28→  agent_prompt?: string;
 29→  agent_rules?: AgentRules;
 30→  created_at: string;
 31→  updated_at: string;
 32→}
 33→
 34→export interface AgentRules {
 35→  on_major_release?: boolean;
 36→  on_minor_release?: boolean;
 37→  on_security_patch?: boolean;
 38→  version_pattern?: string;
 39→}
 40→
 41→export interface ProjectInput {
 42→  name: string;
 43→  description?: string;
 44→  agent_prompt?: string;
 45→  agent_rules?: AgentRules;
 46→}
 47→
 48→export interface Source {
 49→  id: string;
 50→  project_id: string;
 51→  provider: string;
 52→  repository: string;
 53→  poll_interval_seconds: number;
 54→  enabled: boolean;
 55→  config?: Record<string, unknown>;
 56→  version_filter_include?: string;
 57→  version_filter_exclude?: string;
 58→  exclude_prereleases?: boolean;
 59→  last_polled_at?: string;
 60→  last_error?: string;
 61→  created_at: string;
 62→  updated_at: string;
 63→}
 64→
 65→export interface SourceInput {
 66→  provider: string;
 67→  repository: string;
 68→  poll_interval_seconds: number;
 69→  enabled: boolean;
 70→  config?: Record<string, unknown>;
 71→  version_filter_include?: string;
 72→  version_filter_exclude?: string;
 73→  exclude_prereleases?: boolean;
 74→}
 75→
 76→export interface Release {
 77→  id: string;
 78→  source_id: string;
 79→  version: string;
 80→  raw_data?: Record<string, unknown>;
 81→  released_at?: string;
 82→  created_at: string;
 83→  project_id?: string;
 84→  project_name?: string;
 85→  provider?: string;
 86→  repository?: string;
 87→  excluded?: boolean;
 88→  semantic_release_id?: string;
 89→  semantic_release_status?: string;
 90→  semantic_release_urgency?: string;
 91→}
 92→
 93→export interface ContextSource {
 94→  id: string;
 95→  project_id: string;
 96→  type: string;
 97→  name: string;
 98→  config: Record<string, unknown>;
 99→  created_at: string;
100→  updated_at: string;
101→}
102→
103→export interface ContextSourceInput {
104→  type: string;
105→  name: string;
106→  config: Record<string, unknown>;
107→}
108→
109→export interface SemanticRelease {
110→  id: string;
111→  project_id: string;
112→  project_name?: string;
113→  version: string;
114→  report?: SemanticReport;
115→  status: string;
116→  error?: string;
117→  created_at: string;
118→  completed_at?: string;
119→}
120→
121→export interface SemanticReport {
122→  subject?: string;
123→  urgency?: string;
124→  urgency_reason?: string;
125→  status_checks?: string[];
126→  changelog_summary?: string;
127→  download_commands?: string[];
128→  download_links?: string[];
129→  summary?: string;
130→  availability?: string;
131→  adoption?: string;
132→  recommendation?: string;
133→  // Backward compat — old reports may still have these
134→  risk_level?: string;
135→  risk_reason?: string;
136→}
137→
138→export interface AgentRun {
139→  id: string;
140→  project_id: string;
141→  semantic_release_id?: string;
142→  trigger: string;
143→  status: string;
144→  prompt_used?: string;
145→  error?: string;
146→  started_at?: string;
147→  completed_at?: string;
148→  created_at: string;
149→}
150→
151→export interface NotificationChannel {
152→  id: string;
153→  name: string;
154→  type: string;
155→  config: Record<string, unknown>;
156→  created_at: string;
157→  updated_at: string;
158→}
159→
160→export interface ChannelInput {
161→  type: string;
162→  name: string;
163→  config: Record<string, unknown>;
164→}
165→
166→export interface Subscription {
167→  id: string;
168→  channel_id: string;
169→  type: "source_release" | "semantic_release";
170→  source_id?: string;
171→  project_id?: string;
172→  version_filter?: string;
173→  created_at: string;
174→}
175→
