 28→export default function TodoPage() {
 29→  return (
 30→    <Suspense>
 31→      <TodoPageInner />
 32→    </Suspense>
 33→  );
 34→}
 35→
 36→function TodoPageInner() {
 37→  const { t } = useTranslation();
 38→  const [activeTab, setActiveTab] = useState<StatusTab>("pending");
 39→  const [page, setPage] = useState(1);
 40→  const [aggregated, setAggregated] = useState(true);
 41→  const [confirmDialog, setConfirmDialog] = useState<{
 42→    action: string;
 43→    projectName?: string;
 44→    version?: string;
 45→    onConfirm: () => void;
 46→  } | null>(null);
 47→
 48→  const TABS: { key: StatusTab; label: string }[] = [
 49→    { key: "pending", label: t("todo.tabPending") },
 50→    { key: "acknowledged", label: t("todo.tabAcknowledged") },
 51→    { key: "resolved", label: t("todo.tabResolved") },
 52→  ];
 53→
 54→  /* Fetch todos for active tab */
 55→  const { data, isLoading, mutate } = useSWR(
 56→    ["todos", activeTab, page, aggregated],
 57→    () => todosApi.list(activeTab, page, PER_PAGE, aggregated)
 58→  );
 59→
 60→  /* Fetch counts for all three tabs */
 61→  const { data: pendingData, mutate: mutatePending } = useSWR(
 62→    ["todos-count", "pending", aggregated],
 63→    () => todosApi.list("pending", 1, 1, aggregated)
 64→  );
 65→  const { data: ackedData, mutate: mutateAcked } = useSWR(
 66→    ["todos-count", "acknowledged", aggregated],
 67→    () => todosApi.list("acknowledged", 1, 1, aggregated)
 68→  );
 69→  const { data: resolvedData, mutate: mutateResolved } = useSWR(
 70→    ["todos-count", "resolved", aggregated],
 71→    () => todosApi.list("resolved", 1, 1, aggregated)
 72→  );
 73→
 74→  const counts: Record<StatusTab, number> = {
 75→    pending: pendingData?.meta?.total ?? 0,
 76→    acknowledged: ackedData?.meta?.total ?? 0,
 77→    resolved: resolvedData?.meta?.total ?? 0,
 78→  };
 79→
 80→  /* SSE revalidation */
 81→  const revalidateAll = useCallback(() => {
 82→    mutate();
 83→    mutatePending();
 84→    mutateAcked();
 85→    mutateResolved();
 86→  }, [mutate, mutatePending, mutateAcked, mutateResolved]);
 87→
 88→  useEffect(() => {
 89→    const baseUrl = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
 90→    const es = new EventSource(`${baseUrl}/events`);
 91→    es.onmessage = () => revalidateAll();
 92→    es.onerror = () => {
 93→      /* EventSource auto-reconnects; nothing to do */
 94→    };
 95→    return () => es.close();
 96→  }, [revalidateAll]);
 97→
 98→  const items: Todo[] = data?.data ?? [];
 99→  const total = data?.meta?.total ?? 0;
100→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
101→  const startRow = (page - 1) * PER_PAGE + 1;
102→  const endRow = Math.min(page * PER_PAGE, total);
103→
104→  /* Action handlers with optimistic updates */
105→  const handleAcknowledge = async (id: string) => {
106→    /* Optimistic: remove from current list */
107→    mutate(
108→      (prev) => {
109→        if (!prev) return prev;
110→        return {
111→          ...prev,
112→          data: prev.data.filter((t) => t.id !== id),
113→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
114→        };
115→      },
116→      { revalidate: false }
117→    );
118→    try {
119→      await todosApi.acknowledge(id, true);
120→    } catch {
121→      /* Revert on failure */
122→    }
123→    revalidateAll();
124→  };
125→
126→  const handleResolve = async (id: string, cascade = true) => {
127→    mutate(
128→      (prev) => {
129→        if (!prev) return prev;
130→        return {
131→          ...prev,
132→          data: prev.data.filter((t) => t.id !== id),
133→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
134→        };
135→      },
136→      { revalidate: false }
137→    );
138→    try {
139→      await todosApi.resolve(id, cascade);
140→    } catch {
141→      /* Revert on failure */
142→    }
143→    revalidateAll();
144→  };
145→
146→  const handleReopen = async (id: string) => {
147→    mutate(
148→      (prev) => {
149→        if (!prev) return prev;
150→        return {
151→          ...prev,
152→          data: prev.data.filter((t) => t.id !== id),
153→          meta: prev.meta ? { ...prev.meta, total: prev.meta.total - 1 } : prev.meta,
154→        };
155→      },
156→      { revalidate: false }
157→    );
158→    try {
159→      await todosApi.reopen(id);
160→    } catch {
161→      /* Revert on failure */
162→    }
163→    revalidateAll();
164→  };
165→
166→  const tabLabelMap: Record<StatusTab, string> = {
167→    pending: t("todo.tabPending").toLowerCase(),
168→    acknowledged: t("todo.tabAcknowledged").toLowerCase(),
169→    resolved: t("todo.tabResolved").toLowerCase(),
170→  };
171→
172→  return (
173→    <div className="space-y-6">
174→      {/* Page title */}
175→      <div>
176→        <h1
177→          className="text-foreground"
178→          style={{
179→            fontFamily: "var(--font-raleway)",
180→            fontSize: "24px",
181→            fontWeight: 700,
182→          }}
183→        >
184→          {t("todo.title")}
185→        </h1>
186→        <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
187→          {t("todo.description")}
188→        </p>
189→      </div>
190→
191→      {/* Status tabs + aggregated toggle */}
192→      <div className="flex items-center justify-between">
193→        <div className="flex items-center gap-2">
194→          {TABS.map((tab) => {
195→            const isActive = activeTab === tab.key;
196→            return (
197→              <button
198→                key={tab.key}
199→                onClick={() => {
200→                  setActiveTab(tab.key);
201→                  setPage(1);
202→                }}
203→                className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors"
204→                style={{
205→                  fontFamily: "var(--font-dm-sans)",
206→                  fontSize: "13px",
207→                  fontWeight: 500,
208→                  color: isActive ? "var(--foreground)" : "var(--text-secondary)",
209→                  backgroundColor: isActive ? "var(--mono-bg)" : "transparent",
210→                  border: isActive ? "1px solid var(--border)" : "1px solid transparent",
211→                }}
212→              >
213→                {tab.label}
214→                <span
215→                  className="inline-flex items-center justify-center rounded-full px-1.5 text-[11px] font-medium leading-none"
216→                  style={{
217→                    minWidth: "18px",
218→                    height: "18px",
219→                    backgroundColor: isActive ? "var(--border)" : "var(--mono-bg)",
220→                    color: isActive ? "var(--foreground)" : "var(--text-muted)",
221→                  }}
222→                >
223→                  {counts[tab.key]}
224→                </span>
225→              </button>
226→            );
227→          })}
228→        </div>
229→
230→        <button
231→          onClick={() => {
232→            setAggregated((v) => !v);
233→            setPage(1);
234→          }}
235→          className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 transition-colors"
236→          style={{
237→            fontFamily: "var(--font-dm-sans)",
238→            fontSize: "13px",
239→            fontWeight: 500,
240→            color: aggregated ? "var(--foreground)" : "var(--text-secondary)",
241→            backgroundColor: aggregated ? "var(--mono-bg)" : "transparent",
242→            border: aggregated ? "1px solid var(--border)" : "1px solid transparent",
243→          }}
