  1→// web/components/dashboard/unified-feed.tsx
  2→"use client";
  3→
  4→import useSWR from "swr";
  5→import Link from "next/link";
  6→import {
  7→  releases as releasesApi,
  8→  semanticReleases as srApi,
  9→} from "@/lib/api/client";
 10→import { VersionChip } from "@/components/ui/version-chip";
 11→import { getProviderIcon } from "@/components/ui/provider-badge";
 12→import { Sparkles } from "lucide-react";
 13→import type { Release, SemanticRelease } from "@/lib/api/types";
 14→import { timeAgo } from "@/lib/format";
 15→import { useTranslation } from "@/lib/i18n/context";
 16→
 17→type FeedItemType =
 18→  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
 19→  | { kind: "semantic"; data: SemanticRelease; projectName?: string };
 20→
 21→function getTimestamp(item: FeedItemType): number {
 22→  if (item.kind === "release") {
 23→    return new Date(item.data.released_at ?? item.data.created_at).getTime();
 24→  }
 25→  return new Date(item.data.created_at).getTime();
 26→}
 27→
 28→function getTimeStr(item: FeedItemType): string {
 29→  if (item.kind === "release") {
 30→    return item.data.released_at ?? item.data.created_at;
 31→  }
 32→  return item.data.created_at;
 33→}
 34→
 35→function ProviderIcon({ provider }: { provider: string }) {
 36→  const icon = getProviderIcon(provider);
 37→  if (!icon) return <div className="h-3.5 w-3.5 shrink-0" />;
 38→  return icon({ size: 14, className: "shrink-0 text-text-muted" });
 39→}
 40→
 41→export function UnifiedFeed() {
 42→  const { t } = useTranslation();
 43→
 44→  const { data: feedItems, isLoading } = useSWR(
 45→    "unified-feed",
 46→    async () => {
 47→      // Fetch recent releases and semantic releases globally (server sorts by recency)
 48→      const [releasesRes, srRes] = await Promise.all([
 49→        releasesApi.list(1, 15).catch(() => null),
 50→        srApi.listAll(1, 15).catch(() => null),
 51→      ]);
 52→
 53→      const items: FeedItemType[] = [];
 54→
 55→      if (releasesRes?.data) {
 56→        for (const rel of releasesRes.data) {
 57→          items.push({
 58→            kind: "release",
 59→            data: rel,
 60→            repository: rel.repository,
 61→            provider: rel.provider,
 62→            projectName: rel.project_name,
 63→          });
 64→        }
 65→      }
 66→
 67→      if (srRes?.data) {
 68→        for (const sr of srRes.data) {
 69→          items.push({
 70→            kind: "semantic",
 71→            data: sr,
 72→            projectName: sr.project_name,
 73→          });
 74→        }
 75→      }
 76→
 77→      // Merge and sort by timestamp descending, take first 15
 78→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
 79→      return items.slice(0, 15);
 80→    },
 81→    { refreshInterval: 30_000 }
 82→  );
 83→
 84→  if (isLoading) {
 85→    return (
 86→      <div
 87→        className="rounded-lg bg-surface py-16 text-center border border-border"
 88→      >
 89→        <p
 90→          className="text-text-secondary"
 91→          style={{
 92→            fontFamily: "var(--font-dm-sans)",
 93→            fontSize: "13px",
 94→          }}
 95→        >
 96→          {t("dashboard.feed.loading")}
 97→        </p>
 98→      </div>
 99→    );
100→  }
101→
102→  if (!feedItems || feedItems.length === 0) {
103→    return null; // Empty state handled by parent
104→  }
105→
106→  return (
107→    <div
108→      className="flex flex-col rounded-lg bg-surface border border-border"
109→      style={{ height: "336px" }}
110→    >
111→      {/* Header */}
112→      <div
113→        className="flex items-center justify-between px-5 py-4 shrink-0 border-b border-border"
114→      >
115→        <p
116→          className="text-xs uppercase tracking-[0.08em] text-text-secondary"
117→          style={{
118→            fontFamily: "var(--font-dm-sans)",
119→            fontSize: "12px",
120→          }}
121→        >
122→          {t("dashboard.feed.recentActivity")}
123→        </p>
124→      </div>
125→
126→      {/* Feed items -- scrollable */}
127→      <div className="flex-1 overflow-y-auto">
128→        {feedItems.map((item, idx) => (
129→          <FeedEntry
130→            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
131→            item={item}
132→            isLast={idx === feedItems.length - 1}
133→          />
134→        ))}
135→      </div>
136→    </div>
137→  );
138→}
139→
140→function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
141→  const { t } = useTranslation();
142→
143→  if (item.kind === "semantic") {
144→    const sr = item.data;
145→    const urgency = sr.report?.urgency?.toUpperCase();
146→    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";
147→
148→    return (
149→      <Link
150→        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
151→        className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-background"
152→        style={{
153→          borderBottom: isLast ? undefined : "1px solid var(--border)",
154→        }}
155→      >
156→        {/* AI icon */}
157→        <Sparkles className="h-3.5 w-3.5 shrink-0 text-text-muted" />
158→
159→        {/* Content */}
160→        <div className="min-w-0 flex-1 flex items-center gap-2">
161→          <span
162→            className="truncate text-text-secondary"
163→            style={{
164→              fontFamily: "var(--font-dm-sans)",
165→              fontSize: "13px",
166→            }}
167→          >
168→            {item.projectName ?? t("dashboard.feed.unknownProject")}
169→          </span>
170→          {isUrgent && (
171→            <span
172→              className="inline-flex items-center rounded px-1 py-0.5 text-[10px] font-semibold leading-none"
173→              style={{
174→                backgroundColor: urgency === "CRITICAL" ? "#fff1f2" : "#fff8f0",
175→                color: urgency === "CRITICAL" ? "#dc2626" : "#d97706",
176→              }}
177→            >
178→              {urgency}
179→            </span>
180→          )}
181→        </div>
182→
183→        {/* Version + timestamp */}
184→        <div className="flex items-center gap-3 shrink-0">
185→          <VersionChip version={sr.version} />
186→          <span
187→            className="whitespace-nowrap text-text-muted"
188→            style={{
189→              fontFamily: "var(--font-dm-sans)",
190→              fontSize: "12px",
191→            }}
192→          >
193→            {timeAgo(getTimeStr({ kind: "semantic", data: sr }))}
194→          </span>
195→        </div>
196→      </Link>
197→    );
198→  }
199→
200→  // Raw release
201→  const release = item.data;
202→
203→  return (
204→    <Link
205→      href={`/releases/${release.id}`}
206→      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-background"
207→      style={{
208→        borderBottom: isLast ? undefined : "1px solid var(--border)",
209→      }}
210→    >
211→      {/* Provider icon */}
212→      {item.provider ? (
213→        <ProviderIcon provider={item.provider} />
214→      ) : (
215→        <div className="h-3.5 w-3.5 shrink-0" />
216→      )}
217→
218→      {/* Content */}
219→      <div className="min-w-0 flex-1 flex items-center gap-2">
220→        <span
221→          className="truncate text-text-secondary"
222→          style={{
223→            fontFamily: "'JetBrains Mono', monospace",
224→            fontSize: "13px",
225→          }}
226→        >
227→          {item.repository ?? release.source_id.slice(0, 12)}
228→        </span>
229→        {item.projectName && (
230→          <span
231→            className="truncate text-text-muted"
232→            style={{
233→              fontFamily: "var(--font-dm-sans)",
234→              fontSize: "12px",
235→            }}
236→          >
237→            · {item.projectName}
238→          </span>
239→        )}
240→      </div>
241→
242→      {/* Version + timestamp */}
243→      <div className="flex items-center gap-3 shrink-0">
244→        <VersionChip version={release.version} />
245→        <span
246→          className="whitespace-nowrap text-text-muted"
247→          style={{
248→            fontFamily: "var(--font-dm-sans)",
249→            fontSize: "12px",
250→          }}
251→        >
252→          {timeAgo(release.released_at ?? release.created_at)}
253→        </span>
254→      </div>
255→    </Link>
256→  );
257→}
