package api

import (
	"context"
	"net/http"

	"github.com/sentioxyz/changelogue/internal/models"
)

// TodosStore defines the data access interface for TODO operations.
type TodosStore interface {
	ListTodos(ctx context.Context, status string, page, perPage int, aggregated bool) ([]models.Todo, int, error)
	GetTodo(ctx context.Context, id string) (*models.Todo, error)
	AcknowledgeTodo(ctx context.Context, id string, cascade bool) error
	ResolveTodo(ctx context.Context, id string, cascade bool) error
	ReopenTodo(ctx context.Context, id string) error
}

// TodosHandler handles HTTP requests for release TODOs.
type TodosHandler struct {
	store     TodosStore
	publicURL string
}

// NewTodosHandler creates a new TodosHandler.
func NewTodosHandler(store TodosStore, publicURL string) *TodosHandler {
	return &TodosHandler{store: store, publicURL: publicURL}
}

// List returns a paginated list of TODOs, optionally filtered by status.
func (h *TodosHandler) List(w http.ResponseWriter, r *http.Request) {
	page, perPage := ParsePagination(r)
	status := r.URL.Query().Get("status")
	aggregated := r.URL.Query().Get("aggregated") == "true"

	todos, total, err := h.store.ListTodos(r.Context(), status, page, perPage, aggregated)
	if err != nil {
		RespondError(w, r, http.StatusInternalServerError, "internal_error", err.Error())
		return
	}
	if todos == nil {
		todos = []models.Todo{}
	}
	RespondList(w, r, http.StatusOK, todos, page, perPage, total)
}

// Get returns a single TODO by ID.
func (h *TodosHandler) Get(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	todo, err := h.store.GetTodo(r.Context(), id)
	if err != nil {
		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
		return
	}
	RespondJSON(w, r, http.StatusOK, todo)
}

// Acknowledge marks a TODO as acknowledged. Supports both PATCH (API) and GET with redirect (notification links).
func (h *TodosHandler) Acknowledge(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	cascade := r.URL.Query().Get("cascade") == "true"
	if err := h.store.AcknowledgeTodo(r.Context(), id, cascade); err != nil {
		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
		return
	}

	// If redirect=true, send 302 to the frontend todo page.
	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
		return
	}

	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "acknowledged"})
}

// Resolve marks a TODO as resolved. Supports both PATCH (API) and GET with redirect (notification links).
func (h *TodosHandler) Resolve(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	cascade := r.URL.Query().Get("cascade") == "true"
	if err := h.store.ResolveTodo(r.Context(), id, cascade); err != nil {
		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
		return
	}

	// If redirect=true, send 302 to the frontend todo page.
	if r.URL.Query().Get("redirect") == "true" && h.publicURL != "" {
		http.Redirect(w, r, h.publicURL+"/todo", http.StatusFound)
		return
	}

	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "resolved"})
}

// Reopen marks a TODO as pending again, clearing acknowledged/resolved timestamps.
func (h *TodosHandler) Reopen(w http.ResponseWriter, r *http.Request) {
	id := r.PathValue("id")
	if err := h.store.ReopenTodo(r.Context(), id); err != nil {
		RespondError(w, r, http.StatusNotFound, "not_found", "Todo not found")
		return
	}

	RespondJSON(w, r, http.StatusOK, map[string]string{"status": "pending"})
}

func (s *PgStore) ListTodos(ctx context.Context, status string, page, perPage int, aggregated bool) ([]models.Todo, int, error) {
	// Base WHERE clause
	whereClause := ""
	countArgs := []any{}
	if status != "" {
		whereClause = ` WHERE t.status = $1`
		countArgs = append(countArgs, status)
	}

	// Shared FROM/JOIN clause.
	fromClause := `
		FROM release_todos t
		LEFT JOIN releases r ON r.id = t.release_id
		LEFT JOIN sources src ON src.id = r.source_id
		LEFT JOIN projects p1 ON p1.id = src.project_id
		LEFT JOIN semantic_releases sr ON sr.id = t.semantic_release_id
		LEFT JOIN projects p2 ON p2.id = sr.project_id
	`

	// Shared select columns with aliases for subquery use.
	selectCols := `
			t.id, t.release_id, t.semantic_release_id, t.status,
			t.created_at, t.acknowledged_at, t.resolved_at,
			COALESCE(p1.id, p2.id, gen_random_uuid())::text AS project_id,
			COALESCE(p1.name, p2.name, '') AS project_name,
			COALESCE(r.version, sr.version, '') AS version,
			COALESCE(src.provider, '') AS provider,
			COALESCE(src.repository, '') AS repository,
			CASE WHEN t.release_id IS NOT NULL THEN 'release' ELSE 'semantic' END AS todo_type`

	var countQuery string
	var query string
	offset := (page - 1) * perPage

	if aggregated {
		// Aggregated: keep only the latest todo per grouping key.
		// Group by (source_id) for release todos, (project_id) for semantic todos.
		partitionExpr := `CASE WHEN t.release_id IS NOT NULL THEN r.source_id::text ELSE sr.project_id::text END`

		countQuery = `
			SELECT COUNT(*) FROM (
				SELECT t.id,
					ROW_NUMBER() OVER (PARTITION BY ` + partitionExpr + ` ORDER BY t.created_at DESC) AS rn
				` + fromClause + whereClause + `
			) sub WHERE sub.rn = 1`

		query = `
			SELECT id, release_id, semantic_release_id, status,
				created_at, acknowledged_at, resolved_at,
				project_id, project_name, version, provider, repository, todo_type
			FROM (
				SELECT ` + selectCols + `,
					ROW_NUMBER() OVER (PARTITION BY ` + partitionExpr + ` ORDER BY t.created_at DESC) AS rn
				` + fromClause + whereClause + `
			) sub WHERE sub.rn = 1
			ORDER BY created_at DESC`
	} else {
		countQuery = `SELECT COUNT(*) FROM release_todos t` + whereClause
		query = `SELECT ` + selectCols + fromClause + whereClause + ` ORDER BY t.created_at DESC`
	}

	// Execute count query
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, countArgs...).Scan(&total); err != nil {
		return nil, 0, fmt.Errorf("count todos: %w", err)
	}

	// Add pagination
	queryArgs := append([]any{}, countArgs...)
	argIdx := len(queryArgs) + 1
	query += fmt.Sprintf(` LIMIT $%d OFFSET $%d`, argIdx, argIdx+1)
	queryArgs = append(queryArgs, perPage, offset)

	rows, err := s.pool.Query(ctx, query, queryArgs...)
	if err != nil {
		return nil, 0, fmt.Errorf("list todos: %w", err)
	}
	defer rows.Close()

	var todos []models.Todo
	for rows.Next() {
		var t models.Todo
		if err := rows.Scan(
			&t.ID, &t.ReleaseID, &t.SemanticReleaseID, &t.Status,
			&t.CreatedAt, &t.AcknowledgedAt, &t.ResolvedAt,
			&t.ProjectID, &t.ProjectName, &t.Version, &t.Provider, &t.Repository, &t.TodoType,
		); err != nil {
			return nil, 0, fmt.Errorf("scan todo: %w", err)
		}
		todos = append(todos, t)
	}
	return todos, total, nil
}

func (s *PgStore) GetTodo(ctx context.Context, id string) (*models.Todo, error) {
	var t models.Todo
	err := s.pool.QueryRow(ctx, `
		SELECT
			t.id, t.release_id, t.semantic_release_id, t.status,
			t.created_at, t.acknowledged_at, t.resolved_at,

