                              {opt.label}
                            </span>
                            {isActive && <Check size={12} className="ml-auto text-accent" />}
                          </button>
                        );
                      })}
                  </div>
                </div>
              )}

              {selectedConfig && selectedConfig.type === "date-range" && (
                <div className="w-52 py-1">
