"use client";

import { useState, useRef, useEffect } from "react";
import { X, Plus, Search, Check } from "lucide-react";

/* Types */

export interface FilterOption {
  value: string;
  label: string;
}

export interface FilterConfig {
  key: string;
  label: string;
  type: "select" | "boolean" | "date-range";
  options?: FilterOption[];
  defaultValue?: string;
}

export interface FilterBarProps {
  filters: FilterConfig[];
  value: Record<string, string>;
  onChange: (value: Record<string, string>) => void;
}

/* Date presets */

const DATE_PRESETS: FilterOption[] = [
  { value: "7d", label: "Last 7 days" },
  { value: "30d", label: "Last 30 days" },
  { value: "90d", label: "Last 90 days" },
  { value: "1y", label: "Last year" },
];

export function expandDatePreset(preset: string): { date_from: string; date_to?: string } {
  const now = new Date();
  let from: Date;
  switch (preset) {
    case "7d":
      from = new Date(now.getTime() - 7 * 86400000);
      break;
    case "30d":
      from = new Date(now.getTime() - 30 * 86400000);
      break;
    case "90d":
      from = new Date(now.getTime() - 90 * 86400000);
      break;
    case "1y":
      from = new Date(now.getTime() - 365 * 86400000);
      break;
    default:
      return { date_from: preset };
  }
  return { date_from: from.toISOString().slice(0, 10) };
}

/* Chip sub-component */

function Chip({
  label,
  displayValue,
  onRemove,
  onClick,
}: {
  label: string;
  displayValue: string;
  onRemove: () => void;
