    const next = { ...value };
    delete next[key];
    if (key === "date") {
      delete next["date_from"];
      delete next["date_to"];
    }
    onChange(next);
  };

  const setFilter = (key: string, val: string) => {
    onChange({ ...value, [key]: val });
    setPopoverOpen(false);
    setSelectedType(null);
    setSearch("");
